arguments.argument:
event_inherited()
if global.gamePaused=false
{
  speed=bulletSpeed
  
  if arcTime>0
  {
    arcTime-=1
    if arcTime>20
    {
      if image_xscale=1
        direction-=3
      else
        direction+=3
    }
    else
    {
      if image_xscale=1
        direction-=6
      else
        direction+=6
    }
  }
  if image_xscale=1
    image_angle-=20
  else
    image_angle+=20
  
  if isCollisionLeft(1)
    instance_destroy()
  if isCollisionRight(1)
    instance_destroy()
  if isCollisionBottom(1)
    instance_destroy()
  if isCollisionTop(1)
    instance_destroy()
  lifeTime-=1
  if lifeTime=0
    instance_destroy()
}
else
  speed=0
